import * as React from 'react';
import Box from '@mui/material/Box';
import Container from '@mui/material/Container';
import { Typography } from '@mui/material';

import image from "./images/DSCF1941-min.jpg";

import CssBaseline from '@mui/material/CssBaseline';

function Hero () {
	return (
		<>
			<CssBaseline />
			<Box
				display='flex'
				height={'100vh'}
				sx={{
					alignItems: 'center',
					backgroundColor: 'grey',
					backgroundImage: `linear-gradient(rgba(255,255,255,0.5), rgba(255,255,255,0.5)), url(${image})`,
					backgroundSize: 'cover',
					backgroundRepeat: 'no-repeat',
					backgroundPosition: 'center',
					// opacity: 0.5,
				}}
			>
				<Box flex='1' width={100} sx={{ marginLeft: 5, marginRight: 5, marginTop: 3 }}>
					<Typography variant='h1' sx={{ backgroundColor: 'blue', textAlign: 'center', fontSize: 45 }}>
						Title Here
					</Typography>
					<Typography variant='h2' sx={{ backgroundColor: 'white', textAlign: 'center', fontSize: 20 }}>
						Subtitle here
					</Typography>
				</Box>
			</Box>
		</>
	)
}

export default Hero;
